 2→
 3→export function serializeProject(project) {
 4→  return {
 5→    schemaVersion: CURRENT_SCHEMA_VERSION,
 6→    version: CURRENT_PROJECT_FILE_VERSION,
 7→    data: project,
 8→    savedAt: new Date().toISOString(),
 9→  };
