 1→import { serializeProject } from './serialize';
 2→import { deserializeProject } from './deserialize';
 3→import { localStorageBackend } from './localStorageBackend';
 4→import { validateBackend } from './backendInterface';
 5→
 6→let backend = localStorageBackend;
 7→
 8→export function setBackend(b) {
 9→  backend = validateBackend(b);
10→}
11→
12→export async function saveProject(project) {
13→  const serialized = serializeProject(project);
14→  await backend.save(project.id, project.name, serialized);
15→  return serialized.savedAt;
16→}
17→
18→export async function loadProject(projectId) {
19→  const json = await backend.load(projectId);
20→  if (!json) throw new Error('Project not found');
21→  return deserializeProject(json);
22→}
23→
24→export async function listProjects() {
25→  return backend.list();
26→}
27→
28→export async function deleteProject(projectId) {
29→  await backend.delete(projectId);
