 1→export class PersistenceError extends Error {
 2→  constructor(message, code) {
 3→    super(message);
 4→    this.name = 'PersistenceError';
 5→    this.code = code;
 6→  }
 7→}
 8→
 9→export class ProjectValidationError extends PersistenceError {
10→  constructor(message, errors = []) {
11→    super(message, 'VALIDATION_FAILED');
12→    this.name = 'ProjectValidationError';
13→    this.errors = errors;
14→  }
15→}
16→
17→export class UnsupportedVersionError extends PersistenceError {
18→  constructor(version) {
19→    super(`Unsupported schema version: ${version}`, 'UNSUPPORTED_VERSION');
20→    this.name = 'UnsupportedVersionError';
21→    this.version = version;
22→  }
23→}
24→
25→export class CorruptedDataError extends PersistenceError {
26→  constructor(message) {
27→    super(message || 'Project data is corrupted', 'CORRUPTED_DATA');
28→    this.name = 'CorruptedDataError';
29→  }
30→}
