  1→import { ProjectValidationError } from './errors';
  2→import { PHASE_ASSIGNABLE_KEYS } from '@/domain/phaseAssignments';
  3→
  4→export function validateProjectStructure(project) {
  5→  const errors = [];
  6→
  7→  if (!project || typeof project !== 'object') {
  8→    errors.push({ path: '', message: 'Project must be a non-null object' });
  9→    return errors;
 10→  }
 11→  if (typeof project.id !== 'string' || !project.id) {
 12→    errors.push({ path: 'id', message: 'Project must have a non-empty string id' });
 13→  }
 14→  if (typeof project.name !== 'string' || !project.name) {
 15→    errors.push({ path: 'name', message: 'Project must have a non-empty string name' });
 16→  }
 17→  if (!Array.isArray(project.floors) || project.floors.length === 0) {
 18→    errors.push({ path: 'floors', message: 'Project must have a non-empty floors array' });
 19→    return errors;
 20→  }
 21→
 22→  project.floors.forEach((floor, fi) => {
 23→    if (!floor.id) {
 24→      errors.push({ path: `floors[${fi}].id`, message: 'Floor must have an id' });
 25→    }
 26→    if (!Array.isArray(floor.walls)) {
 27→      errors.push({ path: `floors[${fi}].walls`, message: 'Floor must have a walls array' });
 28→    }
 29→
 30→    for (const door of (floor.doors || [])) {
 31→      if (!door.id) errors.push({ path: `floors[${fi}].doors`, message: 'Door missing id' });
 32→      if (!door.wallId) errors.push({ path: `floors[${fi}].doors`, message: `Door ${door.id || '?'} missing wallId` });
 33→    }
 34→
 35→    for (const win of (floor.windows || [])) {
 36→      if (!win.id) errors.push({ path: `floors[${fi}].windows`, message: 'Window missing id' });
 37→      if (!win.wallId) errors.push({ path: `floors[${fi}].windows`, message: `Window ${win.id || '?'} missing wallId` });
 38→    }
 39→  });
 40→
 41→  return errors;
 42→}
 43→
 44→export function validateProjectReferences(project) {
 45→  const warnings = [];
 46→
 47→  const floorIds = new Set(project.floors.map((f) => f.id));
 48→  const phaseIds = new Set((project.phases || []).map((p) => p.id));
 49→
 50→  for (const floor of project.floors) {
 51→    const wallIds = new Set((floor.walls || []).map((w) => w.id));
 52→    const landingIds = new Set((floor.landings || []).map((l) => l.id));
 53→    const columnIds = new Set((floor.columns || []).map((c) => c.id));
 54→
 55→    for (const door of (floor.doors || [])) {
 56→      if (door.wallId && !wallIds.has(door.wallId)) {
 57→        warnings.push({ path: `floor ${floor.id} door ${door.id}`, message: `References non-existent wall ${door.wallId}` });
 58→      }
 59→    }
 60→
 61→    for (const win of (floor.windows || [])) {
 62→      if (win.wallId && !wallIds.has(win.wallId)) {
 63→        warnings.push({ path: `floor ${floor.id} window ${win.id}`, message: `References non-existent wall ${win.wallId}` });
 64→      }
 65→    }
 66→
 67→    for (const beam of (floor.beams || [])) {
 68→      if (beam.startRef?.columnId && !columnIds.has(beam.startRef.columnId)) {
 69→        warnings.push({ path: `floor ${floor.id} beam ${beam.id}`, message: `startRef references non-existent column ${beam.startRef.columnId}` });
 70→      }
 71→      if (beam.endRef?.columnId && !columnIds.has(beam.endRef.columnId)) {
 72→        warnings.push({ path: `floor ${floor.id} beam ${beam.id}`, message: `endRef references non-existent column ${beam.endRef.columnId}` });
 73→      }
 74→    }
 75→
 76→    for (const stair of (floor.stairs || [])) {
 77→      if (stair.floorRelation?.fromFloorId && !floorIds.has(stair.floorRelation.fromFloorId)) {
 78→        warnings.push({ path: `floor ${floor.id} stair ${stair.id}`, message: `fromFloorId references non-existent floor ${stair.floorRelation.fromFloorId}` });
 79→      }
 80→      if (stair.floorRelation?.toFloorId && !floorIds.has(stair.floorRelation.toFloorId)) {
 81→        warnings.push({ path: `floor ${floor.id} stair ${stair.id}`, message: `toFloorId references non-existent floor ${stair.floorRelation.toFloorId}` });
 82→      }
 83→      if (stair.startLandingAttachment?.landingId && !landingIds.has(stair.startLandingAttachment.landingId)) {
 84→        warnings.push({ path: `floor ${floor.id} stair ${stair.id}`, message: `startLandingAttachment references non-existent landing ${stair.startLandingAttachment.landingId}` });
 85→      }
 86→      if (stair.endLandingAttachment?.landingId && !landingIds.has(stair.endLandingAttachment.landingId)) {
 87→        warnings.push({ path: `floor ${floor.id} stair ${stair.id}`, message: `endLandingAttachment references non-existent landing ${stair.endLandingAttachment.landingId}` });
 88→      }
 89→    }
 90→
 91→    for (const slab of (floor.slabs || [])) {
 92→      if (slab.floorId && !floorIds.has(slab.floorId)) {
 93→        warnings.push({ path: `floor ${floor.id} slab ${slab.id}`, message: `floorId references non-existent floor ${slab.floorId}` });
 94→      }
 95→    }
 96→
 97→    // Check phaseId references on all phase-assignable objects
 98→    for (const key of PHASE_ASSIGNABLE_KEYS) {
 99→      for (const obj of (floor[key] || [])) {
100→        if (obj.phaseId && !phaseIds.has(obj.phaseId)) {
101→          warnings.push({ path: `floor ${floor.id} ${key} ${obj.id}`, message: `phaseId references non-existent phase ${obj.phaseId}` });
102→        }
103→      }
104→    }
105→  }
106→
107→  // Check phaseId on roof system and truss systems
108→  if (project.roofSystem?.phaseId && !phaseIds.has(project.roofSystem.phaseId)) {
109→    warnings.push({ path: 'roofSystem', message: `phaseId references non-existent phase ${project.roofSystem.phaseId}` });
110→  }
111→  for (const ts of (project.trussSystems || [])) {
112→    if (ts.phaseId && !phaseIds.has(ts.phaseId)) {
113→      warnings.push({ path: `trussSystem ${ts.id}`, message: `phaseId references non-existent phase ${ts.phaseId}` });
114→    }
115→  }
116→
117→  // Check viewport phaseId references
118→  for (const sheet of (project.sheets || [])) {
119→    for (const vp of (sheet.viewports || [])) {
120→      if (vp.phaseId && !phaseIds.has(vp.phaseId)) {
121→        warnings.push({ path: `sheet ${sheet.id} viewport ${vp.id}`, message: `phaseId references non-existent phase ${vp.phaseId}` });
122→      }
123→    }
124→  }
125→
126→  return warnings;
127→}
128→
129→export function repairBrokenReferences(project) {
130→  const floorIds = new Set(project.floors.map((f) => f.id));
131→  const phaseIds = new Set((project.phases || []).map((p) => p.id));
132→
133→  const repairedFloors = project.floors.map((floor) => {
134→    const wallIds = new Set((floor.walls || []).map((w) => w.id));
135→    const landingIds = new Set((floor.landings || []).map((l) => l.id));
136→
137→    // Remove doors/windows pointing to non-existent walls
138→    const doors = (floor.doors || []).filter((d) => !d.wallId || wallIds.has(d.wallId));
139→    const windows = (floor.windows || []).filter((w) => !w.wallId || wallIds.has(w.wallId));
140→
141→    // Nullify invalid stair landing attachments
142→    const stairs = (floor.stairs || []).map((stair) => {
143→      let changed = false;
144→      let startLandingAttachment = stair.startLandingAttachment;
145→      let endLandingAttachment = stair.endLandingAttachment;
146→
147→      if (startLandingAttachment?.landingId && !landingIds.has(startLandingAttachment.landingId)) {
148→        startLandingAttachment = null;
149→        changed = true;
150→      }
151→      if (endLandingAttachment?.landingId && !landingIds.has(endLandingAttachment.landingId)) {
152→        endLandingAttachment = null;
153→        changed = true;
154→      }
155→      return changed ? { ...stair, startLandingAttachment, endLandingAttachment } : stair;
156→    });
157→
158→    // Nullify invalid phaseId references on floor objects
159→    const repairedFloor = { ...floor, doors, windows, stairs };
160→    for (const key of PHASE_ASSIGNABLE_KEYS) {
161→      const arr = repairedFloor[key];
162→      if (!Array.isArray(arr)) continue;
163→      repairedFloor[key] = arr.map((obj) =>
164→        obj.phaseId && !phaseIds.has(obj.phaseId)
165→          ? { ...obj, phaseId: null }
166→          : obj,
167→      );
168→    }
169→
170→    return repairedFloor;
171→  });
172→
173→  // Nullify invalid phaseId on roof system
174→  let roofSystem = project.roofSystem;
175→  if (roofSystem?.phaseId && !phaseIds.has(roofSystem.phaseId)) {
176→    roofSystem = { ...roofSystem, phaseId: null };
177→  }
178→
179→  // Nullify invalid phaseId on truss systems
180→  const trussSystems = (project.trussSystems || []).map((ts) =>
181→    ts.phaseId && !phaseIds.has(ts.phaseId)
182→      ? { ...ts, phaseId: null }
183→      : ts,
184→  );
185→
186→  // Nullify invalid viewport phaseId references
187→  const sheets = (project.sheets || []).map((sheet) => ({
188→    ...sheet,
189→    viewports: (sheet.viewports || []).map((vp) =>
190→      vp.phaseId && !phaseIds.has(vp.phaseId)
191→        ? { ...vp, phaseId: null, phaseViewMode: 'all' }
192→        : vp,
193→    ),
194→  }));
195→
196→  return { ...project, floors: repairedFloors, roofSystem, trussSystems, sheets };
197→}
198→
199→export function validateAndRepair(project) {
200→  const structuralErrors = validateProjectStructure(project);
201→  if (structuralErrors.length > 0) {
202→    throw new ProjectValidationError(
203→      `Project failed structural validation: ${structuralErrors.map((e) => e.message).join('; ')}`,
204→      structuralErrors,
205→    );
206→  }
207→
208→  const warnings = validateProjectReferences(project);
209→  if (warnings.length > 0) {
210→    console.warn('[persistence] Referential integrity warnings:', warnings);
211→    return repairBrokenReferences(project);
212→  }
213→
214→  return project;
215→}
