 27→function canUseOpenFilePicker() {
 28→  return typeof window !== 'undefined' && typeof window.showOpenFilePicker === 'function';
 29→}
 30→
 31→function canUseSaveFilePicker() {
 32→  return typeof window !== 'undefined' && typeof window.showSaveFilePicker === 'function';
 33→}
 34→
 35→function downloadBlob(blob, fileName) {
 36→  const objectUrl = URL.createObjectURL(blob);
 37→  const link = document.createElement('a');
 38→  link.href = objectUrl;
 39→  link.download = fileName;
 40→  link.style.display = 'none';
 41→  document.body.appendChild(link);
 42→  link.click();
 43→  link.remove();
 44→
 45→  window.setTimeout(() => {
 46→    URL.revokeObjectURL(objectUrl);
 47→  }, 0);
 48→}
