 24→function migrateV14toV15(project) {
 25→  if (!Array.isArray(project.sheets)) {
 26→    project.sheets = [];
 27→  }
 28→  if (project.roofSystem === undefined) {
 29→    project.roofSystem = null;
 30→  }
 31→  if (!Array.isArray(project.trussSystems)) {
 32→    project.trussSystems = [];
