1011→function createInitialState(project) {
1012→  const synced = syncProjectStructures({
1013→    ...project,
1014→    floors: sortFloors(project.floors || []),
1015→  });
1016→  return {
1017→    project: synced,
1018→    isDirty: false,
1019→    lastSavedAt: null,
1020→    savedSnapshot: snapshotProject(synced),
1021→    history: [],
1022→    future: [],
1023→  };
1024→}
